module top_module(
  input         clock, reset, 
  output [3:0]  count
);reg [3:0] unused_counter;

  always @ (posedge clock) begin
    if (reset) begin
      unused_counter <= 4'b0;
    end else begin
      unused_counter <= unused_counter + 1;
    end
  end

  assign count = unused_counter;

endmodule
